class Solution:
    def hasPathSum(self, root, targetSum):
        paths = []
        def walk(node, acc):
            if node is None:
                return
            acc = acc + [node.val]
            if node.left is None and node.right is None:
                paths.append(acc)
                return
            walk(node.left, acc)
            walk(node.right, acc)
        walk(root, [])
        return any(sum(p) == targetSum for p in paths)

